import axios from 'axios';

const apiClient = axios.create({
  baseURL: 'https://sipr.freeddns.org',
  withCredentials: true,
  xsrfCookieName: 'csrftoken',
  xsrfHeaderName: 'X-CSRFToken',
});

// You can add interceptors here to handle 401/403 errors globally
apiClient.interceptors.response.use(
  response => response,
  error => {
    if (error.response.status === 403) {
      console.error("CSRF or Permission Error");
    }
    return Promise.reject(error);
  }
);

// Add this to your src/services/api.js
apiClient.interceptors.request.use(config => {
    // You could force a CSRF refresh here if the cookie is missing
    return config;
});

export default apiClient;
